package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;
import java.nio.charset.Charset;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.forName("UTF-8");
    }

    @Test
    public void testPrintCreatesCSVPrinter() throws Exception {
        // Use reflection to create OutputStreamWriter and CSVPrinter mocks manually,
        // since mockConstruction is not available in Mockito 3.
        // We'll spy on CSVFormat to override print method to use mocks.

        // Mock FileOutputStream constructor (cannot mock constructors easily, so we mock FileOutputStream itself)
        // Instead, we mock OutputStreamWriter constructor to return a mock instance.

        // Create a mock OutputStreamWriter
        OutputStreamWriter mockWriter = mock(OutputStreamWriter.class);

        // Create a spy for CSVFormat to override the print(File, Charset) method
        CSVFormat spyFormat = spy(csvFormat);

        // Use reflection to get the CSVPrinter constructor
        Constructor<CSVPrinter> printerConstructor = CSVPrinter.class.getDeclaredConstructor(Appendable.class, CSVFormat.class);
        printerConstructor.setAccessible(true);

        // Create a mock CSVPrinter
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // When new CSVPrinter(...) is called inside print, we cannot intercept directly,
        // so we override print(File, Charset) method in spy to return our mockPrinter.

        doReturn(mockPrinter).when(spyFormat).print(any(File.class), any(Charset.class));

        // Call the overridden print method
        CSVPrinter printer = spyFormat.print(mockFile, charset);

        assertNotNull(printer);
        assertSame(mockPrinter, printer);
    }

    @Test
    public void testPrintThrowsIOException() throws IOException {
        // We cannot mock constructor to throw IOException with Mockito 3,
        // so we simulate by creating a subclass of CSVFormat that overrides print(File, Charset) to throw IOException.

        CSVFormat csvFormatIOException = new CSVFormat(DEFAULT.getDelimiter(), DEFAULT.getQuoteCharacter(),
                DEFAULT.getQuoteMode(), DEFAULT.getCommentMarker(), DEFAULT.getEscapeCharacter(),
                DEFAULT.getIgnoreSurroundingSpaces(), DEFAULT.getIgnoreEmptyLines(), DEFAULT.getRecordSeparator(),
                DEFAULT.getNullString(), DEFAULT.getHeaderComments(), DEFAULT.getHeader(), DEFAULT.getSkipHeaderRecord(),
                DEFAULT.getAllowMissingColumnNames(), DEFAULT.getIgnoreHeaderCase(), DEFAULT.getTrim(),
                DEFAULT.getTrailingDelimiter()) {
            @Override
            public CSVPrinter print(File out, Charset charset) throws IOException {
                throw new IOException("Simulated IOException");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> {
            csvFormatIOException.print(mockFile, charset);
        });
        assertEquals("Simulated IOException", thrown.getMessage());
    }
}
